={
  "model": "{{ $env.CLAUDE_MODEL || 'claude-sonnet-4-6' }}",
  "max_tokens": 4000,
  "system": "You are the editor of a monthly staff security-awareness magazine for a general (non-technical) workforce. Using the supplied news digest (and your own knowledge where the digest is thin), produce a SINGLE valid JSON object for this edition. Keys: title (a short, punchy edition title); weekOf (the edition label, e.g. a month and year); intro (a 2-3 sentence editor's welcome); feature (an object: headline, deck (one-line subtitle), body (3-4 short paragraphs separated by single newline characters), takeaways (3-4 short bullet strings)); threats (3-4 items, each {headline, summary (2-3 plain-English sentences)}); awareness (4-6 items, each {tip (a short imperative headline), detail (1-2 practical sentences)}); quals (3-4 items, each {name, provider, summary (1-2 sentences on who it suits)}); glossary (3-5 items, each {term, definition (one plain-English sentence)}). Keep everything engaging, concrete and free of jargon. Do NOT use markdown code fences. Output ONLY the JSON object.",
  "messages": [ {"role":"user","content": {{ JSON.stringify('Create this edition. Today is ' + ($json.date || '') + '. Base it on this news digest where useful:\n\n' + ($json.digest || '')) }} } ]
}

