// Parse the analyst's JSON magazine and build the cover-image prompt.
const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;            // Ollama
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text; // Claude
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
if (!data || typeof data !== 'object') {
  data = { title: 'Security Awareness Digest', weekOf: '', intro: 'This edition could not be generated in full; please re-run.', feature: null, threats: [], awareness: [], quals: [], glossary: [] };
}
const date = (($('Aggregate Sources').first() || {}).json || {}).date || new Date().toISOString().slice(0, 10);
const title = data.title || 'Security Awareness Digest';
const coverPrompt = 'Wide cinematic, semi-realistic editorial cover illustration for a premium corporate SECURITY-AWARENESS magazine titled "' + title + '". Bright modern office, diverse professionals, calm and trustworthy mood; soft natural window light; teal and deep-navy colour grade; strong empty space on the left third for a title overlay. No text, no words, no letters, no logos, no watermark, no charts, no screenshots.';
return [{ json: { data: data, title: title, date: date, coverPrompt: coverPrompt } }];

// Generate the magazine cover image via the shared image provider (graceful:
// empty string => the renderer falls back to a branded gradient cover).
const j = $json || {};
let cover = '';
const key = $env.OPENAI_IMAGE_API_KEY || $env.OPENAI_API_KEY;
const wantImages = (($env.LEARNING_HUB_COVER_IMAGE || $env.CYBER_SECTION_IMAGES || 'true').toString().toLowerCase() !== 'false');
if (wantImages && key && j.coverPrompt) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1') + '/images/generations',
      headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
      body: { model: ($env.IMAGE_MODEL || 'gpt-image-1'), prompt: j.coverPrompt, size: ($env.IMAGE_SIZE || '1024x1536'), n: 1 },
      json: true, timeout: 180000
    });
    const b64 = resp && resp.data && resp.data[0] && resp.data[0].b64_json;
    if (b64) cover = 'data:image/png;base64,' + b64;
  } catch (e) { cover = ''; }
}
return [{ json: Object.assign({}, j, { cover: cover }) }];

// Render the staff security-awareness magazine as one premium, print-ready A4 HTML
// (cover + editorial + feature + threats + human-firewall + skills + glossary).
// Magazine-grade layout: full-bleed cover with an "Inside this issue" panel (so it
// looks intentional even with no cover image), strong section headers, a two-column
// feature with pull-quote and drop-cap, and tidy card grids. Gotenberg -> PDF.
// Returns the parsed magazine data alongside the HTML so the course can use it.
const j = $json || {};
const data = j.data || {};
const date = j.date || new Date().toISOString().slice(0, 10);
const title = j.title || data.title || 'Security Awareness Digest';
const weekOf = data.weekOf || '';
const cover = j.cover || '';
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
function paras(s){ return String(s==null?'':s).split(/\n+/).map(function(p){return p.trim();}).filter(Boolean).map(function(p){return '<p>'+esc(p)+'</p>';}).join(''); }
const A = function(x){ return Array.isArray(x)?x:[]; };
function firstSentence(s){ var m=String(s||'').match(/^[\s\S]*?[.!?](\s|$)/); return (m?m[0]:String(s||'')).trim(); }

const f = data.feature || {};
const threats = A(data.threats), aw = A(data.awareness), quals = A(data.quals), gloss = A(data.glossary);

const CSS = ""
+"@page{size:A4;margin:16mm 15mm 17mm} @page cover{margin:0} *{box-sizing:border-box}"
+"body{margin:0;font-family:Georgia,'Times New Roman',serif;color:#16202b;line-height:1.5;font-size:11.5pt}"
+".s-sans{font-family:-apple-system,'Segoe UI',Roboto,Arial,sans-serif}"
// running footer (repeats each printed page in the bottom margin)
+".runfoot{position:fixed;bottom:7mm;left:15mm;right:15mm;display:flex;justify-content:space-between;font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:8pt;letter-spacing:1px;text-transform:uppercase;color:#9aa6b2}"
// cover
+".cover{page:cover;position:relative;width:210mm;height:297mm;overflow:hidden;background:#0A1A2F;color:#fff;break-after:page}"
+".cover .bg{position:absolute;inset:0;background-size:cover;background-position:center;z-index:0}"
+".cover .bg.ph{background:radial-gradient(120% 80% at 78% 12%,#13507a 0,#0A1A2F 55%),linear-gradient(160deg,#0A1A2F,#0E2233 60%,#0E7C86 140%)}"
+".cover .wm{position:absolute;right:-60mm;top:18mm;width:180mm;height:180mm;opacity:.06;z-index:0}"
+".cover .grad{position:absolute;inset:0;background:linear-gradient(180deg,rgba(8,18,28,.15),rgba(8,18,28,.75));z-index:1}"
+".cover .inner{position:absolute;inset:0;z-index:2;display:flex;flex-direction:column;justify-content:space-between;padding:18mm}"
+".cover .brandbar{display:flex;justify-content:space-between;align-items:center;font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:10pt;letter-spacing:2px;text-transform:uppercase;font-weight:700;color:#9fe4d8}"
+".cover .mid{margin-top:auto}"
+".cover .kick{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:11pt;letter-spacing:5px;text-transform:uppercase;color:#E7C76A;font-weight:800}"
+".cover h1{font-size:40pt;line-height:1.04;margin:8px 0 0;font-weight:700}"
+".cover .edition{font-family:-apple-system,Arial,sans-serif;font-size:11pt;color:#cfe0e6;letter-spacing:1px;margin-top:8px}"
+".cover .stand{font-size:13pt;color:#eaf2f5;font-style:italic;margin-top:12px;max-width:150mm}"
+".cover .toc{margin-top:16mm;border-top:2px solid rgba(201,162,75,.6);padding-top:10px}"
+".cover .toc .tl{font-family:-apple-system,Arial,sans-serif;font-size:9pt;letter-spacing:3px;text-transform:uppercase;color:#E7C76A;font-weight:800;margin-bottom:8px}"
+".cover .toc ul{list-style:none;margin:0;padding:0;column-count:2;column-gap:12mm}"
+".cover .toc li{font-family:-apple-system,Arial,sans-serif;font-size:11pt;color:#eaf2f5;padding:4px 0 4px 16px;position:relative;break-inside:avoid}"
+".cover .toc li:before{content:'';position:absolute;left:0;top:8px;width:8px;height:8px;background:#C9A24B;transform:rotate(45deg)}"
// section header
+".sec{margin:0 0 7mm}"
+".eyebrow{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:9pt;letter-spacing:3px;text-transform:uppercase;color:#0E7C86;font-weight:800}"
+".sec h2{font-size:21pt;color:#0A1A2F;margin:2px 0 0;font-weight:700;line-height:1.1}"
+".sec .hr{height:3px;background:linear-gradient(90deg,#C9A24B 0,#C9A24B 40px,#E2E6EC 40px);margin:7px 0 11px}"
+"p{margin:0 0 8px}"
+".cols{column-count:2;column-gap:9mm}"
+".cols p{margin:0 0 8px;text-align:justify}"
// feature
+".feature .fhead{font-size:25pt;color:#0A1A2F;font-weight:700;line-height:1.08;margin:0 0 2px}"
+".feature .deck{font-style:italic;color:#5A6472;font-size:13pt;margin:0 0 10px}"
+".pull{font-size:16pt;font-style:italic;color:#0E7C86;line-height:1.35;border-left:4px solid #C9A24B;padding:4px 0 4px 16px;margin:4px 0 12px;break-inside:avoid}"
+".take{background:#F4F6F9;border:1px solid #E2E6EC;border-left:4px solid #0E7C86;border-radius:10px;padding:12px 16px;margin-top:10px;break-inside:avoid}"
+".take .th{font-family:-apple-system,Arial,sans-serif;font-size:9pt;letter-spacing:2px;text-transform:uppercase;color:#0A1A2F;font-weight:800;margin-bottom:6px}"
+".take ul{margin:0;padding-left:18px}.take li{font-size:11pt;margin:5px 0}"
// card grids (inline-block: robust in Chromium + weasyprint)
+".grid{font-size:0;margin-top:2px}"
+".card{display:inline-block;width:48.5%;vertical-align:top;margin:0 3% 9px 0;background:#fff;border:1px solid #E2E6EC;border-radius:10px;padding:12px 14px;break-inside:avoid}"
+".card:nth-child(even){margin-right:0}"
+".card h3{font-family:-apple-system,'Segoe UI',Arial,sans-serif;font-size:12pt;color:#0A1A2F;margin:0 0 5px;line-height:1.25}"
+".card p{font-size:10.5pt;color:#46505c;margin:0;line-height:1.4}"
+".tcard{border-left:4px solid #B02525}"
+".tip{display:inline-block;width:48.5%;vertical-align:top;margin:0 3% 9px 0;border:1px solid #E2E6EC;border-radius:10px;padding:11px 13px 11px 44px;position:relative;background:#fff;break-inside:avoid}"
+".tip:nth-child(even){margin-right:0}"
+".tip .n{position:absolute;left:12px;top:12px;width:24px;height:24px;border-radius:50%;background:#0E7C86;color:#fff;font-family:Arial;font-size:11pt;font-weight:800;text-align:center;line-height:24px}"
+".tip h3{font-family:-apple-system,Arial,sans-serif;font-size:11.5pt;color:#0A1A2F;margin:0 0 2px}.tip p{font-size:10.5pt;color:#46505c;margin:0}"
+".qual{border:1px solid #E2E6EC;border-radius:10px;padding:11px 15px;margin:0 0 8px;break-inside:avoid}"
+".qual h3{font-family:-apple-system,Arial,sans-serif;font-size:12.5pt;color:#0A1A2F;margin:0}"
+".qual .prov{font-family:-apple-system,Arial,sans-serif;font-size:8.5pt;letter-spacing:1px;text-transform:uppercase;color:#0E7C86;font-weight:800;margin:2px 0 5px}"
+".qual p{font-size:10.5pt;color:#46505c;margin:0}"
+".gloss{font-size:0}"
+".gterm{display:inline-block;width:48.5%;vertical-align:top;margin:0 3% 8px 0;font-size:10.5pt;color:#46505c;break-inside:avoid;border-bottom:1px solid #eef1f5;padding-bottom:6px}"
+".gterm:nth-child(even){margin-right:0}.gterm b{color:#0A1A2F}";

const wm = '<svg class="wm" viewBox="0 0 24 24" fill="none" stroke="#9fe4d8" stroke-width="0.6"><path d="M12 3l7 3v5c0 4.5-3 7.6-7 9-4-1.4-7-4.5-7-9V6z"/><path d="M9 12l2 2 4-4"/></svg>';

// ---- cover ----
const toc = [];
if (f && f.headline) toc.push('Feature &middot; ' + esc(f.headline));
if (threats.length) toc.push('Emerging Threats');
if (aw.length) toc.push('The Human Firewall &mdash; ' + aw.length + ' habits');
if (quals.length) toc.push('Skills &amp; Qualifications');
if (gloss.length) toc.push('Jargon Buster');

let html = '<!doctype html><html><head><meta charset="utf-8"><style>' + CSS + '</style></head><body>';
html += '<div class="runfoot s-sans"><span>Security Awareness &middot; Learning Hub</span><span>' + esc(weekOf || date) + '</span></div>';
html += '<section class="cover">'
 + (cover ? ('<div class="bg" style="background-image:url(' + cover + ')"></div>') : '<div class="bg ph"></div>')
 + wm + '<div class="grad"></div>'
 + '<div class="inner"><div class="brandbar"><span>Security Awareness</span><span>Learning Hub</span></div>'
 + '<div class="mid"><div class="kick">Staff Awareness Magazine</div>'
 + '<h1>' + esc(title) + '</h1>'
 + '<div class="edition">' + esc(weekOf || date) + ' Edition</div>'
 + (data.intro ? ('<div class="stand">' + esc(firstSentence(data.intro)) + '</div>') : '')
 + (toc.length ? ('<div class="toc"><div class="tl">Inside this issue</div><ul>' + toc.map(function(t){return '<li>' + t + '</li>';}).join('') + '</ul></div>') : '')
 + '</div></div></section>';

function header(eyebrow, t){ return '<div class="eyebrow">' + esc(eyebrow) + '</div><h2>' + esc(t) + '</h2><div class="hr"></div>'; }

// editorial
if (data.intro) {
  html += '<section class="sec">' + header('From the editor', 'Welcome to this edition')
    + '<div class="cols">' + paras(data.intro) + '</div></section>';
}
// feature
if (f && (f.headline || f.body)) {
  const pull = (A(f.takeaways)[0]) || f.deck || '';
  html += '<section class="sec feature">' + header('Feature', f.headline || 'In focus')
    + (f.deck ? ('<div class="deck">' + esc(f.deck) + '</div>') : '')
    + (pull ? ('<div class="pull">&ldquo;' + esc(pull) + '&rdquo;</div>') : '')
    + '<div class="cols">' + paras(f.body || '') + '</div>'
    + (A(f.takeaways).length ? ('<div class="take"><div class="th">Key takeaways</div><ul>' + A(f.takeaways).map(function(t){return '<li>' + esc(t) + '</li>';}).join('') + '</ul></div>') : '')
    + '</section>';
}
// threats
if (threats.length) {
  html += '<section class="sec">' + header('Threat radar', 'Emerging Threats')
    + '<div class="grid">' + threats.map(function(t){return '<div class="card tcard"><h3>' + esc(t.headline||'') + '</h3><p>' + esc(t.summary||'') + '</p></div>';}).join('') + '</div></section>';
}
// human firewall
if (aw.length) {
  html += '<section class="sec">' + header('Practical habits', 'The Human Firewall')
    + '<div class="grid">' + aw.map(function(a,i){return '<div class="tip"><div class="n">' + (i+1) + '</div><h3>' + esc(a.tip||'') + '</h3><p>' + esc(a.detail||'') + '</p></div>';}).join('') + '</div></section>';
}
// skills
if (quals.length) {
  html += '<section class="sec">' + header('Grow your skills', 'Skills &amp; Qualifications')
    + quals.map(function(q){return '<div class="qual"><h3>' + esc(q.name||'') + '</h3><div class="prov">' + esc(q.provider||'') + '</div><p>' + esc(q.summary||'') + '</p></div>';}).join('') + '</section>';
}
// glossary
if (gloss.length) {
  html += '<section class="sec">' + header('Plain English', 'Jargon Buster')
    + '<div class="gloss">' + gloss.map(function(g){return '<div class="gterm"><b>' + esc(g.term||'') + '</b> &mdash; ' + esc(g.definition||'') + '</div>';}).join('') + '</div></section>';
}
html += '</body></html>';

return [{ json: { data: data, html: html, date: date, title: title, weekOf: weekOf, fileSafe: 'learning-hub-' + date } }];

// Wrap the rendered magazine HTML as an index.html binary for Gotenberg.
const meta = $('Render Magazine').first().json;
const buf = Buffer.from(meta.html || '<html></html>', 'utf8');
const bin = await this.helpers.prepareBinaryData(buf, 'index.html', 'text/html');
return [{ json: { date: meta.date, fileSafe: meta.fileSafe }, binary: { data: bin } }];

// Persist the magazine: PDF (from Gotenberg) + HTML + structured JSON archive.
// Carries the parsed magazine data forward so the course can be grounded in it.
const fs = require('fs');
const meta = $('Render Magazine').first().json;
const dir = '/reports/learning-hub';
const archive = '/reports/archive/learning-hub';
const base = meta.fileSafe; // learning-hub-<date>
try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}
try { fs.mkdirSync(archive, { recursive: true }); } catch (e) {}
let pdfPath = '';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  if (buf && buf.length) { fs.writeFileSync(dir + '/' + base + '.pdf', buf); fs.writeFileSync(archive + '/' + base + '.pdf', buf); pdfPath = dir + '/' + base + '.pdf'; }
} catch (e) { pdfPath = ''; }
let htmlOk = false;
try { fs.writeFileSync(dir + '/' + base + '.html', meta.html); htmlOk = true; } catch (e) {}
try { fs.writeFileSync(archive + '/' + base + '.json', JSON.stringify({ title: meta.title, weekOf: meta.weekOf, date: meta.date, data: meta.data }, null, 2)); } catch (e) {}
// Fail loudly (red node) rather than silently green if the output dir is not writable.
if (!htmlOk) throw new Error('Learning Hub: could not write to ' + dir + '. Make /reports writable by the n8n container, e.g. `chmod -R a+rwX reports` on the host.');
return [{ json: {
  ok: true,
  date: meta.date,
  title: meta.title,
  weekOf: meta.weekOf,
  data: meta.data,
  magazinePdf: pdfPath || (dir + '/' + base + '.pdf'),
  magazineHtml: dir + '/' + base + '.html',
  fileSafe: base
} }];

// Build the e-learning "source" grounding text + course metadata from the magazine.
// Output is fed to the module's e-learning workflow (Execute Workflow) and reused
// by Register Publication. Keeps the course strictly about this edition's content.
const m = $json || {};
const data = m.data || {};
const date = m.date || new Date().toISOString().slice(0, 10);
const A = function (x) { return Array.isArray(x) ? x : []; };
function line(s) { return String(s == null ? '' : s).replace(/\s+/g, ' ').trim(); }
const parts = [];
parts.push('MAGAZINE TITLE: ' + (m.title || data.title || 'Security Awareness Digest'));
if (data.intro) parts.push('EDITORIAL: ' + line(data.intro));
const f = data.feature;
if (f && (f.headline || f.body)) {
  parts.push('FEATURE: ' + line(f.headline || '') + (f.deck ? (' — ' + line(f.deck)) : ''));
  if (f.body) parts.push(line(f.body));
  if (A(f.takeaways).length) parts.push('Key takeaways: ' + A(f.takeaways).map(line).join('; '));
}
if (A(data.threats).length) parts.push('EMERGING THREATS: ' + A(data.threats).map(function (t) { return line(t.headline) + ' — ' + line(t.summary); }).join(' | '));
if (A(data.awareness).length) parts.push('AWARENESS TIPS: ' + A(data.awareness).map(function (a) { return line(a.tip) + ': ' + line(a.detail); }).join(' | '));
if (A(data.quals).length) parts.push('SKILLS & QUALIFICATIONS: ' + A(data.quals).map(function (q) { return line(q.name) + ' (' + line(q.provider) + '): ' + line(q.summary); }).join(' | '));
if (A(data.glossary).length) parts.push('GLOSSARY: ' + A(data.glossary).map(function (g) { return line(g.term) + ' = ' + line(g.definition); }).join(' | '));
const source = parts.join('\n');
const title = (m.title || data.title || 'Security Awareness Digest') + ' — Awareness Course';
const pm = parseInt(($env.LEARNING_HUB_PASS_MARK || '80'), 10);
return [{ json: {
  source: source,
  title: title,
  passMark: isNaN(pm) ? 80 : pm,
  format: 'HTML',
  illustrate: (($env.ELEARNING_SECTION_IMAGES || 'true').toString().toLowerCase() !== 'false'),
  publicationId: 'learning-hub-' + date,
  courseId: 'course-learning-hub-' + date,
  releaseDate: date
} }];

// Upsert the publication record the dashboard reads. Links the magazine + the
// derived course, with the release date and 30-day completion window.
const fs = require('fs');
const dir = '/reports/learning-hub';
const file = dir + '/publications.json';
const src = ($('Build Course Source').first() || {}).json || {};
const mag = ($('Write Magazine').first() || {}).json || {};
const course = $json || {};
try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}
let store = { updated: '', publications: [] };
try { const cur = JSON.parse(fs.readFileSync(file, 'utf8')); if (cur && Array.isArray(cur.publications)) store = cur; } catch (e) {}
const entry = {
  id: src.publicationId || ('learning-hub-' + (src.releaseDate || '')),
  title: mag.title || src.title || 'Security Awareness Digest',
  kind: 'magazine',
  releaseDate: src.releaseDate || mag.date || new Date().toISOString().slice(0, 10),
  deadlineDays: 30,
  magazine: { pdf: mag.magazinePdf || '', html: mag.magazineHtml || '' },
  course: { id: src.courseId || '', html: course.html || course.file || '', title: src.title || '', passMark: src.passMark || 80 }
};
store.publications = store.publications.filter(function (p) { return p && p.id !== entry.id; });
store.publications.unshift(entry);
store.publications.sort(function (a, b) { return String(b.releaseDate).localeCompare(String(a.releaseDate)); });
